// data/cityHubContent.ts
// Rich 5-section content for 20 priority city hub pages at /location/<slug>/.
// Used by CityPageClient when present (falls back to generic rendering for
// the 76 non-priority cities that still use the base locationProfiles data).
//
// British English throughout. No em dashes. Apostrophes as \u2019.

export interface CityHubServiceBlurb {
  serviceSlug: string;
  headline: string;
  hook: string;
}

export interface CityHubFaq {
  question: string;
  answer: string;
}

export interface CityHubContent {
  slug: string;
  introDeep: string;
  ecosystemDeep: string;
  whyMatchHere: string;
  serviceBlurbs: CityHubServiceBlurb[];
  faqs: CityHubFaq[];
  closer: string;
}

